const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

function itemBasePremium(item: Item): number {
  const base = BASE_PREMIUMS[item.type];
  if (base === undefined) {
    throw new Error(`Unknown item type: ${item.type}`);
  }
  return base;
}

function quotePremium(items: Item[]): number {
  let policyBase = 0;
  let itemSurcharges = 0;
  for (const item of items) {
    const base = itemBasePremium(item);
    policyBase += base;
    itemSurcharges += base * FIRST_INSURANCE_RATE;
  }
  const total = policyBase + itemSurcharges + PROCESSING_FEE;
  return Math.ceil(total);
}

export function runScenario(scenario: Scenario): ScenarioResult {
  const results: StepResult[] = [];
  for (const step of scenario.steps) {
    if (step.op === 'quote') {
      results.push({ premium: quotePremium(step.items) });
    }
  }
  return { results };
}

