export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteStep {
  op: 'quote';
  items: Item[];
}

export interface DamageEntry {
  itemType: string;
  amount: number;
}

export interface Incident {
  cause: string;
  damages: DamageEntry[];
}

export interface ClaimStep {
  op: 'claim';
  policy: number;
  incident: Incident;
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioResult {
  results: StepResult[];
}

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

function itemBasePremium(item: Item): number {
  const base = BASE_PREMIUMS[item.type];
  if (base === undefined) {
    throw new Error(`Unknown item type: ${item.type}`);
  }
  return base;
}

const CURSED_RATE = 0.5;

function quotePremium(items: Item[]): number {
  let policyBase = 0;
  let itemSurcharges = 0;
  for (const item of items) {
    const base = itemBasePremium(item);
    policyBase += base;
    itemSurcharges += base * FIRST_INSURANCE_RATE;
    if (item.cursed) {
      itemSurcharges += base * CURSED_RATE;
    }
  }
  const total = policyBase + itemSurcharges + PROCESSING_FEE;
  return Math.ceil(total);
}

export function runScenario(scenario: Scenario): ScenarioResult {
  const results: StepResult[] = [];
  for (const step of scenario.steps) {
    if (step.op === 'quote') {
      results.push({ premium: quotePremium(step.items) });
    }
  }
  return { results };
}

