  }
  let policyAdjustments = 0;
  if (opts.loyal) {
    policyAdjustments -= policyBase * LOYALTY_RATE;
  }
  if (opts.isFollowUp) {
    policyAdjustments -= policyBase * FOLLOWUP_RATE;
  }
  const total = policyBase + itemSurcharges + policyAdjustments + PROCESSING_FEE;
  return Math.ceil(total);
}

export function runScenario(scenario: Scenario): ScenarioResult {
  const results: StepResult[] = [];
  const loyal = scenario.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD;
  let quoteCount = 0;
  for (const step of scenario.steps) {
